import base64, re

golf_b64 = ""

iou_b64 = ""

with open('/workspaces/Buddy_Bet/public/golf_ball.webp', 'wb') as f:
    f.write(base64.b64decode(golf_b64))
with open('/workspaces/Buddy_Bet/public/iou_logo.webp', 'wb') as f:
    f.write(base64.b64decode(iou_b64))
print("Images written")

with open('/workspaces/Buddy_Bet/src/App.jsx', 'r') as f:
    content = f.read()

old = "function Av({name,color,size=44}){return <div style={{width:size,height:size,borderRadius:'50%',background:color,display:'flex',alignItems:'center',justifyContent:'center',color:W,fontWeight:600,fontSize:size/2.5,flexShrink:0}}>{ini(name)}</div>}"
new = "function Av({name,color,size=44}){return <div style={{position:'relative',width:size,height:size,flexShrink:0,display:'inline-flex',alignItems:'center',justifyContent:'center'}}><img src='/golf_ball.webp' alt='' style={{width:size,height:size,filter:'drop-shadow(0 2px 6px rgba(0,0,0,0.25))',display:'block'}}/><span style={{position:'absolute',top:'50%',left:'50%',transform:'translate(-50%,-50%)',color:'#1a5c38',fontWeight:700,fontSize:size/2.5,lineHeight:1,pointerEvents:'none',userSelect:'none'}}>{ini(name)}</span></div>}"

if old in content:
    content = content.replace(old, new)
    with open('/workspaces/Buddy_Bet/src/App.jsx', 'w') as f:
        f.write(content)
    print("App.jsx patched")
else:
    print("Pattern not found - printing Av line:")
    for line in content.split('\n'):
        if 'function Av' in line:
            print(repr(line))
